class Dog:
    def __init__(self, name, age):
        self.name = name
        self.age = age

    def bark(self):
        print(f'{self.name} говорит: Гав!')

    def info(self):
        print(f'Собака {self.name}, возраст: {self.age} лет')

    def human_years(self):
        return self.age * 7  # приблизительный перевод

# Создаём объект и вызываем методы
dog = Dog('Рекс', 3)
dog.bark()          # Рекс говорит: Гав!
dog.info()          # Собака Рекс, возраст: 3 лет
print(dog.human_years())  # 21

class BankAccount:
    def __init__(self, owner, balance=0):
        self.owner = owner
        self.balance = balance

    def deposit(self, amount):
        self.balance += amount
        print(f'Пополнение {amount} руб. Баланс: {self.balance}')

    def withdraw(self, amount):
        if amount > self.balance:
            print('Недостаточно средств')
        else:
            self.balance -= amount
            print(f'Снятие {amount} руб. Баланс: {self.balance}')

    def show(self):
        print(f'Счёт {self.owner}: {self.balance} руб.')

acc = BankAccount('Иван', 1000)
acc.show()           # Счёт Иван: 1000 руб.
acc.deposit(500)     # Пополнение 500 руб. Баланс: 1500
acc.withdraw(200)    # Снятие 200 руб. Баланс: 1300
acc.withdraw(2000)   # Недостаточно средств

